mapper.select:
SELECT a.*, c.name, c.avatar
FROM yw_article a
INNER JOIN yw_auth_product b ON a.spu_id = b.id and b.status='10'
INNER JOIN member_user c ON b.member_id = c.id


        AND a.category = #{reqVO.category}


        AND a.title LIKE CONCAT('%', #{reqVO.title}, '%')


        AND a.author = #{reqVO.author}


        AND a.content LIKE CONCAT('%', #{reqVO.content}, '%')


        AND a.introduction LIKE CONCAT('%', #{reqVO.introduction}, '%')


        AND a.status = #{reqVO.status}


        AND a.recommend_hot = #{reqVO.recommendHot}


        AND a.recommend_banner = #{reqVO.recommendBanner}


        AND a.spu_id = #{reqVO.spuId}


        AND a.classification = #{reqVO.classification}


ORDER BY a.create_time DESC

    LIMIT #{reqVO.limit}
